SELECT CAST(year AS INT) AS year, CAST(month AS INT) AS month, reporting_airline, DepTimeBlk AS dep_time_block, CAST(SUBSTRING(DepTimeBlk, 1, 2) AS INT) AS dep_hour, CASE WHEN CAST(SUBSTRING(DepTimeBlk, 1, 2) AS INT) BETWEEN 6 AND 9 THEN 'Morning Peak (6-9)' WHEN CAST(SUBSTRING(DepTimeBlk, 1, 2) AS INT) BETWEEN 10 AND 14 THEN 'Midday (10-14)' WHEN CAST(SUBSTRING(DepTimeBlk, 1, 2) AS INT) BETWEEN 15 AND 19 THEN 'Evening Peak (15-19)' ELSE 'Off-Peak (20-5)' END AS time_period, COUNT(*) AS total_flights, SUM(CASE WHEN cancelled = 0 AND diverted = 0 THEN 1 ELSE 0 END) AS operated_flights, ROUND(100.0 * SUM(CASE WHEN arrdelay <= 15 AND cancelled = 0 AND diverted = 0 THEN 1 ELSE 0 END) / NULLIF(SUM(CASE WHEN cancelled = 0 AND diverted = 0 THEN 1 ELSE 0 END), 0), 2) AS on_time_pct, ROUND(AVG(CASE WHEN cancelled = 0 THEN depdelay END), 2) AS avg_dep_delay_min, ROUND(AVG(CASE WHEN cancelled = 0 THEN arrdelay END), 2) AS avg_arr_delay_min, ROUND(AVG(CASE WHEN cancelled = 0 THEN taxiout END), 2) AS avg_taxi_out_min, ROUND(100.0 * SUM(CASE WHEN cancelled = 1 THEN 1 ELSE 0 END) / COUNT(*), 2) AS cancellation_rate FROM silver_flights WHERE DepTimeBlk IS NOT NULL AND DepTimeBlk != '' GROUP BY year, month, reporting_airline, DepTimeBlk
